#!/usr/bin/env bash

# Spins up the single-node network (see single-node-network.sh) and drives it
# with transactions generated by the Mina node itself, via the incentivized-
# testnet (ITN) GraphQL API -- the same API the mina-perf-testing orchestrator
# uses. By default it sends simple payments; --zkapps switches to "max cost"
# zkApp commands.
#
# Flow:
#   1. Generate a fresh Ed25519 keypair (for ITN GraphQL authentication);
#   2. Start the single-node network with ITN_FEATURES=1 and --itn-keys, so the
#      seed daemon serves the ITN GraphQL API on seed port + 5 (default 3005);
#   3. Wait for the daemon to be fully initialized (GraphQL up and SYNCED);
#   4. Authenticate against the ITN API ('auth' query, plain Ed25519 signature
#      over the request body) and invoke schedulePayments (or, with --zkapps,
#      scheduleZkappCommands) -- a sequenced mutation, signature over 2-byte
#      big-endian seqno ++ server uuid ++ body.
#
# Send rate: the scheduler emits one transaction every 1/tps seconds. The slot
# is sized to a block of coinbase + fee transfer + 2 user commands (scan-state
# capacity 2^2), so to keep every block occupied the default load aims for 2
# transactions per slot (tps = 2 / slot_seconds). At that rate ~90%+ of blocks
# carry their full 2 commands; the rest fall short only on timing jitter, and
# the mempool does not grow without bound. With --zkapps and full proofs the
# rate is instead capped at 2 / (slot / 0.75) (~1.5 txns/slot): max-cost zkApp
# commands are proving-bound, and exceeding the snark workers' throughput would
# back-pressure the scan state into producing *empty* blocks.
#
# --zkapps first deploys --num-zkapps zkApp accounts (fee paid by the offline
# whale), then emits max-cost commands with --num-updates proof-authorized
# account updates each, i.e. (num-updates + 1) SNARK segments; the default 7
# yields the 8-segment transactions the full-proof presets are dimensioned for.
#
# Duration: --duration-min runs a single fixed window (the zkApp deployment
# phase, if any, counts against it). --indefinite instead reschedules a fresh
# 60-minute window every hour until the script is interrupted.
#
# Dependencies (document per repo policy: get any missing one with
#   nix-shell -p openssl python3 jq):
#   - openssl >= 1.1.1 (Ed25519 keygen and raw signing)
#   - python3 (stdlib only; HTTP + request signing glue)
#   - nix (only when --mina-exe is not provided; see single-node-network.sh)

set -e

SCRIPT_DIR="$(cd "$(dirname "${BASH_SOURCE[0]}")" && pwd)"
REPO_ROOT="$(git -C "${SCRIPT_DIR}" rev-parse --show-toplevel)"

DURATION_MIN=""
INDEFINITE=false
FAST=false
NO_PROOFS=false
EPOCH_MIN=""
STOP_TIME_HOURS=""
ZKAPPS=false
NUM_UPDATES=7
NUM_ZKAPPS=2
MINA_EXE_ARG=""
NETWORK_ROOT="${HOME}/.mina-network"
SEED_BASE_PORT=3000
MEMO_PREFIX="load"
RENEW_WINDOW_MIN=60
PAYMENT_AMOUNT="1000000000"
EXTRA_ARGS=()

help() {
  cat <<EOF
Usage: $(basename "$0") (--duration-min <#> | --indefinite) [options] [-- <extra single-node-network.sh args>]

-d | --duration-min <#> | Run a single fixed window of this many minutes (the
                        | zkApp deployment phase, with --zkapps, counts against it).
--indefinite            | Keep sending forever: reschedule a fresh
                        | ${RENEW_WINDOW_MIN}-minute window every ${RENEW_WINDOW_MIN}
                        | minutes until interrupted. Excludes --duration-min.
--zkapps                | Send max-cost zkApp commands instead of the default
                        | payments load.
--fast                  | Use the fast single-node preset (7 workers, 75s slots).
--no-proofs             | Use the no-proofs single-node preset (proof_level=none,
                        | 1 worker, 2s min slot) for fast iteration.
--epoch-min <#>         | Target epoch length in minutes (48 slots/epoch; the
                        | slot time, and thus the send rate, is derived from it).
--stop-time-hours <#>   | Uptime (hours) after which the daemon stops itself.
                        | Forwarded to single-node-network.sh, which defaults to
                        | 43800 (5 years) so the node does not self-restart;
                        | pass 168 for the upstream ~weekly behaviour.
--num-updates <#>       | (--zkapps only) Proof-authorized account updates per
                        | max-cost command; a command equals num-updates+1 segments.
                        |   Default: ${NUM_UPDATES} (i.e. 8 segments)
--num-zkapps <#>        | (--zkapps only) zkApp accounts to deploy upfront.
                        |   Default: ${NUM_ZKAPPS}
--mina-exe <path>       | Mina executable; built with nix when not provided.
--root <path>           | Network root directory.
                        |   Default: ${NETWORK_ROOT}
-h                      | Show this help.

Anything else is forwarded to single-node-network.sh.
EOF
  exit
}

while [[ "$#" -gt 0 ]]; do
  case "${1}" in
  -d | --duration-min)
    DURATION_MIN="${2}"
    shift
    ;;
  --indefinite)
    INDEFINITE=true
    ;;
  --zkapps)
    ZKAPPS=true
    ;;
  --fast)
    FAST=true
    ;;
  --no-proofs)
    NO_PROOFS=true
    ;;
  --epoch-min)
    EPOCH_MIN="${2}"
    shift
    ;;
  --stop-time-hours)
    STOP_TIME_HOURS="${2}"
    shift
    ;;
  --num-updates)
    NUM_UPDATES="${2}"
    shift
    ;;
  --num-zkapps)
    NUM_ZKAPPS="${2}"
    shift
    ;;
  --mina-exe)
    MINA_EXE_ARG="${2}"
    shift
    ;;
  --root)
    NETWORK_ROOT="${2}"
    shift
    ;;
  -h | --help)
    help
    ;;
  --)
    shift
    EXTRA_ARGS+=("$@")
    break
    ;;
  *)
    EXTRA_ARGS+=("${1}")
    ;;
  esac
  shift
done

if ${INDEFINITE}; then
  if [[ -n "${DURATION_MIN}" ]]; then
    echo "Error: --duration-min and --indefinite are mutually exclusive." >&2
    exit 1
  fi
  DURATION_MIN=${RENEW_WINDOW_MIN}
elif [[ -z "${DURATION_MIN}" ]]; then
  echo "Error: one of --duration-min or --indefinite is required." >&2
  exit 1
fi

for tool in openssl python3; do
  if ! command -v "${tool}" >/dev/null; then
    echo "Error: '${tool}' not found; get it with: nix-shell -p openssl python3" >&2
    exit 1
  fi
done

# Preset / timing flags shared by the slot-time query here and the network
# launch further down.
PRESET_ARGS=()
${FAST} && PRESET_ARGS+=(--fast)
${NO_PROOFS} && PRESET_ARGS+=(--no-proofs)
[[ -n "${EPOCH_MIN}" ]] && PRESET_ARGS+=(--epoch-min "${EPOCH_MIN}")
[[ -n "${STOP_TIME_HOURS}" ]] && PRESET_ARGS+=(--stop-time-hours "${STOP_TIME_HOURS}")

# Ask single-node-network.sh for the exact slot time it will run with, so the
# send rate is derived from the same source of truth.
SLOT_TIME_MS=$("${SCRIPT_DIR}/single-node-network.sh" --print-slot-ms "${PRESET_ARGS[@]}")
SLOT_TIME_S=$(python3 -c "print(${SLOT_TIME_MS} / 1000)")

if ${ZKAPPS} && ! ${NO_PROOFS}; then
  # Full-proof max-cost zkApps are proving-bound; cap at ~1.5 txns/slot so the
  # scan state does not back-pressure into empty blocks.
  TPS=$(python3 -c "print(2 / (${SLOT_TIME_S} / 0.75))")
  RATE_NOTE="proving-bound (~1.5 txns/slot)"
else
  # Payments (and any no-proofs load) are not proving-bound: fill the block's 2
  # user-command slots so ~90%+ of blocks carry 2 transactions.
  TPS=$(python3 -c "print(2 / ${SLOT_TIME_S})")
  RATE_NOTE="block-filling (2 txns/slot)"
fi

# ================================================
# 1. Fresh Ed25519 keypair for ITN GraphQL authentication

ITN_DIR=$(mktemp -d -t mina-itn-load.XXXXXX)
ITN_KEY_PEM="${ITN_DIR}/itn_key.pem"
if ! openssl genpkey -algorithm ed25519 -out "${ITN_KEY_PEM}" 2>/dev/null; then
  echo "Error: this openssl cannot generate Ed25519 keys (need >= 1.1.1)." >&2
  echo "Get a capable one with: nix-shell -p openssl" >&2
  exit 1
fi
# --itn-keys takes the base64 of the raw 32-byte Ed25519 public key (the DER
# encoding is a fixed 12-byte ASN.1 header followed by the raw key).
ITN_PUB=$(openssl pkey -in "${ITN_KEY_PEM}" -pubout -outform DER | tail -c 32 | base64 -w0)
echo "ITN auth keypair at ${ITN_KEY_PEM}, public key ${ITN_PUB}"

cat > "${ITN_DIR}/itn_client.py" <<'PYEOF'
"""Minimal ITN GraphQL client (python3 stdlib + openssl subprocess).

Auth protocol, mirroring mina-perf-testing orchestrator (src/graphql.go) and
the node (src/app/cli/src/init/graphql_internal.ml):
  - 'auth' query:  Authorization: Signature <b64 pk> <b64 sig(body)>
  - mutations:     Authorization: Signature <pk> <sig> ; Sequencing <uuid> <seqno>
    with sig over: 2-byte big-endian seqno ++ uuid string ++ body
"""
import argparse, base64, json, struct, subprocess, sys, tempfile, urllib.request

def openssl(args, **kw):
    return subprocess.run(["openssl", *args], check=True, capture_output=True, **kw).stdout

def sign_b64(key_pem, msg):
    with tempfile.NamedTemporaryFile(dir=tempfile.gettempdir()) as f:
        f.write(msg)
        f.flush()
        sig = openssl(["pkeyutl", "-sign", "-inkey", key_pem, "-rawin", "-in", f.name])
    return base64.b64encode(sig).decode()

def pubkey_b64(key_pem):
    der = openssl(["pkey", "-in", key_pem, "-pubout", "-outform", "DER"])
    return base64.b64encode(der[-32:]).decode()

def post(url, body, auth_header):
    req = urllib.request.Request(
        url, data=body,
        headers={"Content-Type": "application/json", "Authorization": auth_header})
    with urllib.request.urlopen(req, timeout=60) as resp:
        out = json.load(resp)
    if out.get("errors"):
        raise RuntimeError("GraphQL errors: %s" % out["errors"])
    return out["data"]

def do_auth(url, key_pem):
    body = json.dumps(
        {"query": "query { auth { serverUuid signerSequenceNumber } }"}).encode()
    auth_header = "Signature %s %s" % (pubkey_b64(key_pem), sign_b64(key_pem, body))
    data = post(url, body, auth_header)["auth"]
    return data["serverUuid"], int(data["signerSequenceNumber"])

def sequenced_post(url, key_pem, uuid, seqno, body):
    # Sequenced mutations sign over: 2-byte big-endian seqno ++ uuid ++ body.
    msg = struct.pack(">H", seqno) + uuid.encode() + body
    auth_header = "Signature %s %s ; Sequencing %s %d" % (
        pubkey_b64(key_pem), sign_b64(key_pem, msg), uuid, seqno)
    return post(url, body, auth_header)

def main():
    ap = argparse.ArgumentParser()
    ap.add_argument("--url", required=True)
    ap.add_argument("--key", required=True)
    sub = ap.add_subparsers(dest="cmd", required=True)
    sub.add_parser("auth")

    pay = sub.add_parser("schedule-payments")
    pay.add_argument("--sender-sk", required=True)
    pay.add_argument("--receiver-pk", required=True)
    pay.add_argument("--amount", required=True)
    pay.add_argument("--duration-min", type=int, required=True)
    pay.add_argument("--tps", type=float, required=True)
    pay.add_argument("--memo-prefix", default="load")

    sch = sub.add_parser("schedule-max-cost")
    sch.add_argument("--fee-payer-sk", required=True)
    sch.add_argument("--duration-min", type=int, required=True)
    sch.add_argument("--tps", type=float, required=True)
    sch.add_argument("--num-updates", type=int, required=True)
    sch.add_argument("--num-zkapps", type=int, required=True)
    sch.add_argument("--memo-prefix", default="load")

    stp = sub.add_parser("stop")
    stp.add_argument("--handle", required=True)

    args = ap.parse_args()

    uuid, seqno = do_auth(args.url, args.key)
    if args.cmd == "auth":
        print("authenticated: server uuid %s, sequence number %d" % (uuid, seqno))
        return

    if args.cmd == "schedule-payments":
        payment_input = {
            "senders": [args.sender_sk],
            "receiver": args.receiver_pk,
            "amount": args.amount,
            "minFee": "1000000000",
            "maxFee": "2000000000",
            "memoPrefix": args.memo_prefix,
            "tps": args.tps,
            "durationMin": args.duration_min,
        }
        body = json.dumps({
            "query": "mutation($input: PaymentsDetails!) "
                     "{ schedulePayments(input: $input) }",
            "variables": {"input": payment_input},
        }).encode()
        print(sequenced_post(args.url, args.key, uuid, seqno, body)["schedulePayments"])
        return

    if args.cmd == "stop":
        body = json.dumps({
            "query": "mutation($handle: String!) "
                     "{ stopScheduledTransactions(handle: $handle) }",
            "variables": {"handle": args.handle},
        }).encode()
        print(sequenced_post(args.url, args.key, uuid, seqno, body)
              ["stopScheduledTransactions"])
        return

    zkapp_input = {
        "feePayers": [args.fee_payer_sk],
        "numZkappsToDeploy": args.num_zkapps,
        "numNewAccounts": 0,
        "tps": args.tps,
        "durationMin": args.duration_min,
        "memoPrefix": args.memo_prefix,
        "noPrecondition": False,
        # Balance-change bounds are required by the schema but unused by the
        # max-cost generator.
        "minBalanceChange": "0",
        "maxBalanceChange": "1000000000",
        "minNewZkappBalance": "1000000000",
        "maxNewZkappBalance": "2000000000",
        "initBalance": "5000000000",
        "minFee": "1000000000",
        "maxFee": "2000000000",
        "deploymentFee": "1000000000",
        # 0 means accounts return to the generator pool right away, which keeps
        # the per-public-key proof cache hot.
        "accountQueueSize": 0,
        "maxCost": True,
        "maxCostNumUpdates": args.num_updates,
    }
    body = json.dumps({
        "query": "mutation($input: ZkappCommandsDetails!) "
                 "{ scheduleZkappCommands(input: $input) }",
        "variables": {"input": zkapp_input},
    }).encode()
    print(sequenced_post(args.url, args.key, uuid, seqno, body)
          ["scheduleZkappCommands"])

if __name__ == "__main__":
    main()
PYEOF

# ================================================
# 2. Start the single-node network with the ITN GraphQL server enabled

# --itn-keys / --itn-graphql-port only exist on the daemon CLI when
# ITN_FEATURES is set in its environment.
export ITN_FEATURES=1

MINA_EXE_ARGS=()
[[ -n "${MINA_EXE_ARG}" ]] && MINA_EXE_ARGS=(--mina-exe "${MINA_EXE_ARG}")

"${SCRIPT_DIR}/single-node-network.sh" \
  "${PRESET_ARGS[@]}" \
  "${MINA_EXE_ARGS[@]}" \
  --no-value-transfers \
  "${EXTRA_ARGS[@]}" \
  -r "${NETWORK_ROOT}" \
  --itn-keys "${ITN_PUB}" &
NET_PID=$!

cleanup() {
  if [[ -n "${NET_PID}" ]] && kill -0 "${NET_PID}" 2>/dev/null; then
    kill -TERM "${NET_PID}" 2>/dev/null || true
    wait "${NET_PID}" 2>/dev/null || true
  fi
}
trap cleanup EXIT INT TERM

network_died() {
  if ! kill -0 "${NET_PID}" 2>/dev/null; then
    echo "Error: the network exited before the load could be scheduled." >&2
    exit 1
  fi
}

# ================================================
# 3. Wait for the daemon to be fully initialized

REST_URL="http://127.0.0.1:$((SEED_BASE_PORT + 1))/graphql"
ITN_URL="http://127.0.0.1:$((SEED_BASE_PORT + 5))/graphql"

echo "Waiting for the daemon at ${REST_URL} to be SYNCED (this includes the nix build / proving-key generation on first runs)..."
until python3 - "${REST_URL}" <<'PYEOF'
import json, sys, urllib.request
# Quietly report "not ready yet" on any failure (connection refused while the
# daemon is still building/booting, GraphQL not serving yet, ...); the shell
# loop keeps polling.
try:
    req = urllib.request.Request(
        sys.argv[1], data=json.dumps({"query": "query { syncStatus }"}).encode(),
        headers={"Content-Type": "application/json"})
    with urllib.request.urlopen(req, timeout=10) as resp:
        sys.exit(0 if json.load(resp)["data"]["syncStatus"] == "SYNCED" else 1)
except Exception:
    sys.exit(1)
PYEOF
do
  network_died
  sleep 10
done
echo "Daemon is SYNCED."

echo "Waiting for the ITN GraphQL server at ${ITN_URL}..."
until python3 "${ITN_DIR}/itn_client.py" --url "${ITN_URL}" --key "${ITN_KEY_PEM}" auth 2>/dev/null; do
  network_died
  sleep 5
done

# ================================================
# 4. Schedule the transaction load

if [[ -n "${MINA_EXE_ARG}" ]]; then
  MINA_EXE="${MINA_EXE_ARG}"
else
  # single-node-network.sh has finished its nix build by now (the daemon is up).
  MINA_EXE="${REPO_ROOT}/single-node-devnet/bin/mina"
fi

dump-keypair-field() {
  # $1 = privkey path, $2 = "Private key" | "Public key"
  MINA_PRIVKEY_PASS='naughty blue worm' "${MINA_EXE}" advanced dump-keypair \
    --privkey-path "${1}" | sed -n "s/^${2}: //p"
}

# The offline whale holds the bulk of the stake-backing balance and is not used
# as a sender by anything else; use it as the payments sender / zkApp fee payer.
SENDER_SK=$(dump-keypair-field "${NETWORK_ROOT}/offline_whale_keys/offline_whale_account_0" "Private key")
if [[ -z "${SENDER_SK}" ]]; then
  echo "Error: could not extract the sender's private key." >&2
  exit 1
fi
# Payments need a receiver; the online whale is another funded genesis account.
RECEIVER_PK=""
if ! ${ZKAPPS}; then
  RECEIVER_PK=$(dump-keypair-field "${NETWORK_ROOT}/online_whale_keys/online_whale_account_0" "Public key")
  if [[ -z "${RECEIVER_PK}" ]]; then
    echo "Error: could not extract the payment receiver's public key." >&2
    exit 1
  fi
fi

ITN_CLIENT=(python3 "${ITN_DIR}/itn_client.py" --url "${ITN_URL}" --key "${ITN_KEY_PEM}")

schedule_window() {
  # $1 = window duration in minutes; echoes the scheduler handle.
  if ${ZKAPPS}; then
    "${ITN_CLIENT[@]}" schedule-max-cost \
      --fee-payer-sk "${SENDER_SK}" \
      --duration-min "${1}" \
      --tps "${TPS}" \
      --num-updates "${NUM_UPDATES}" \
      --num-zkapps "${NUM_ZKAPPS}" \
      --memo-prefix "${MEMO_PREFIX}"
  else
    "${ITN_CLIENT[@]}" schedule-payments \
      --sender-sk "${SENDER_SK}" \
      --receiver-pk "${RECEIVER_PK}" \
      --amount "${PAYMENT_AMOUNT}" \
      --duration-min "${1}" \
      --tps "${TPS}" \
      --memo-prefix "${MEMO_PREFIX}"
  fi
}

stop_window() {
  [[ -n "${1}" ]] || return 0
  "${ITN_CLIENT[@]}" stop --handle "${1}" >/dev/null 2>&1 || true
}

if ${ZKAPPS}; then
  LOAD_DESC="max-cost zkApp commands (${NUM_UPDATES} updates, $((NUM_UPDATES + 1)) segments)"
else
  LOAD_DESC="payments"
fi
echo "Load: ${LOAD_DESC}; tps=${TPS} [${RATE_NOTE}] at slot ${SLOT_TIME_MS}ms"

if ${INDEFINITE}; then
  echo "Running indefinitely: a ${RENEW_WINDOW_MIN}-minute window is renewed every ${RENEW_WINDOW_MIN} minutes (Ctrl-C to stop)."
  HANDLE=""
  while :; do
    network_died
    # Schedule one minute longer than the renewal interval so the next window
    # starts before this one expires (no gap), then immediately stop the old
    # window so the overlap -- and thus any rate doubling -- lasts only the few
    # seconds between the two calls.
    NEW_HANDLE=$(schedule_window "$((RENEW_WINDOW_MIN + 1))")
    echo "$(date -u +%H:%M:%S) scheduled window, handle: ${NEW_HANDLE}"
    stop_window "${HANDLE}"
    HANDLE="${NEW_HANDLE}"
    sleep "$((RENEW_WINDOW_MIN * 60))"
  done
else
  HANDLE=$(schedule_window "${DURATION_MIN}")
  echo "Scheduler started with handle: ${HANDLE}"
  echo "(The scheduler stops itself after ${DURATION_MIN} minutes; the network keeps running until this script is interrupted.)"
  wait "${NET_PID}"
fi
